import boto3
import logging
import os

# Initialize clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Set up logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    # Extract bucket and object key from the event
    bucket = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']
    
    try:
        # Read image from S3
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()
        
        # Process image (placeholder for image processing logic)
        processed_data = image_data  # Replace with actual processing logic
        
        # Write processed image back to S3
        processed_key = f"processed/{key}"
        s3_client.put_object(Bucket=bucket, Key=processed_key, Body=processed_data)
        
        # Send notification via SNS
        sns_client.publish(
            TopicArn=os.environ['SNS_TOPIC_ARN'],
            Message=f"Image processed and stored at {processed_key}",
            Subject="Image Processing Complete"
        )
        
        # Log to CloudWatch
        logger.info(f"Processed image {key} and stored at {processed_key}")
        
    except Exception as e:
        logger.error(f"Error processing image {key}: {str(e)}")
        raise e

